import './FinancialOverview.css';
function FinancialOverview({transactions}) {
    const currentDate = new Date();
    const currentMonth = currentDate.getMonth();
    const currentYear = currentDate.getFullYear();
    const currentMonthName = currentDate.toLocaleString("default", {
    month: "long",
    });
    const monthlyExpense = transactions
        .filter((transaction) => {
        const transactionDate = new Date(transaction.date);
        return (
            transaction.type === "Expense" &&
            transactionDate.getMonth() === currentMonth &&
            transactionDate.getFullYear() === currentYear
        );
        })
        .reduce((total, transaction) => total + Number(transaction.amount), 0);

    const yearlyExpense = transactions
        .filter((transaction) => {
        const transactionDate = new Date(transaction.date);
        return (
            transaction.type === "Expense" &&
            transactionDate.getFullYear() === currentYear
        );
        })
        .reduce((total, transaction) => total + Number(transaction.amount), 0);
    const yearlyIncome = transactions
        .filter((transaction) => {
        const transactionDate = new Date(transaction.date);
        return (
            transaction.type === "Income" &&
            transactionDate.getFullYear() === currentYear
        );
        })
        .reduce((total, transaction) => total + Number(transaction.amount), 0);
    const totalIncome = transactions
        .filter((transaction) => transaction.type === "Income")
        .reduce((total, transaction) => total + Number(transaction.amount), 0);
    const monthlyIncome = transactions
        .filter((transaction) => {
            const transactionDate = new Date(transaction.date);
        return (
            transaction.type === "Income" &&
            transactionDate.getMonth() === currentMonth
        );
    })
        .reduce((total, transaction) => total + Number(transaction.amount), 0);
    const totalExpense = transactions
        .filter((transaction) => transaction.type === "Expense")
        .reduce((total, transaction) => total + Number(transaction.amount), 0);   
    const monthlySavingsRate = monthlyIncome > 0
    ? ((monthlyIncome - monthlyExpense) / monthlyIncome) * 100 : 0; 
    
    return (
        <>
        <div className="financial-overview">
            Financial Overview
        </div>
        <div className="monthly-overview">
            <p>{currentMonthName} {currentYear}</p>
            <p>Income: ₹{monthlyIncome}</p>
            <p>Expense: ₹{monthlyExpense}</p>
            <p>Savings: {monthlySavingsRate.toFixed(2)}%</p>
        </div>
        <div className="yearly-overview">
            <p>Year {currentYear}</p>
            <p>Income: ₹{yearlyIncome}</p>
            <p>Expense: ₹{yearlyExpense}</p>
            <p>Net Savings: {yearlyIncome-yearlyExpense}</p>
        </div>
        </>
    );
};
export default FinancialOverview;
